mapper.select:
SELECT TV.WRITE_YEAR, TV.DOC_TYPE, TV.DOC_NO, TV.COMP_ID, TV.HR_ID, TV.ORGN_NM, TV.JBRP, TV.WORKING_AT, TV.HAS_CERTIFICATE, TV.ORD_SEQ, TV.USE_YN, TV.CREATED_AT, TV.CREATED_BY, TV.UPDATED_AT, TV.UPDATED_BY, TH.HR_NM FROM ESG.TB_VOLUNTARY_SAFETY_INSPECTOR TV INNER JOIN ESG.TB_HR_INFO TH ON TH.HR_ID = TV.HR_ID WHERE COMP_ID = #{compId}
-- 출력 데이터는 사용중인 데이터만 출력 AND TV.USE_YN = 'Y'
ORDER BY USE_YN DESC, ORD_SEQ

mapper.update:
UPDATE ESG.TB_VOLUNTARY_SAFETY_INSPECTOR
SET WORKING_AT      = #{workingAt},
    HAS_CERTIFICATE = #{hasCertifiCate},
    HR_ID           = #{hrId},
    ORD_SEQ         = #{ordSeq},
    USE_YN          = #{useYn},
    UPDATED_AT      = NOW(),
    UPDATED_BY      = #{updatedBy}
WHERE WRITE_YEAR = #{writeYear}
  AND DOC_TYPE = #{docType}
  AND DOC_NO = #{docNo}

mapper.delete:
UPDATE ESG.TB_VOLUNTARY_SAFETY_INSPECTOR
SET USE_YN     = 'N',
    UPDATED_AT = NOW(),
    UPDATED_BY = #{updatedBy}
WHERE WRITE_YEAR = #{writeYear}
  AND DOC_TYPE = #{docType}
  AND DOC_NO = #{docNo}
